import { createStore } from 'vuex'

export default createStore({
  state: {
    bids: [],
    asks: [],
    updatedBids: [],
    updatedAsks: [],
    updatesArray: [],
    orderBookLastUpdateId: null,
    wsConnection: null,
    currentCurrency: "BTCUSDT"
  },
  mutations: {
    setOrderBook: (state, orderBookData) => {
      state.bids = orderBookData.bids.sort((a, b) => +b[0] - +a[0]);
      state.asks = orderBookData.asks.sort((a, b) => +a[0] - +b[0]);
      state.orderBookLastUpdateId = orderBookData.lastUpdateId;
    },

    setUpdatedAsks: (state, wsData) => {
      // Сделал сортировку, но потом решил переделать алгоритм
      // Заменил поиск через indexOf на бинарный
      // Поменял порядок работы с элементами массива (удаление старых/добаление новых)

      state.updatedAsks = wsData.data.a;

      let ordersCounter = state.asks.length;
      let ordersToAdd = [];
      let ordersToRemove = [];

      // Get current price levels from state
      let currentPrices = [];
      state.asks.forEach(elem => currentPrices.push(+elem[0]))
      currentPrices.sort((a, b) => a - b);

      // Sort an updated array and get best bid
      let updatedOrders = wsData.data.a;
      let updatedPricesSorted = updatedOrders.map(elem => +elem[0]);
      let bestAsk = updatedPricesSorted.sort((a, b) => +a[0] - +b[0])[0];

      // Find updated price in current prices
      for (let i = 0; i < updatedPricesSorted.length; i++) {
        // Search for price
        let priceIndex = binarySearch(currentPrices, updatedPricesSorted[i]);
        
        if (priceIndex !== -1) {
          // Price level needs to be updated
          let newAmount = +updatedOrders[i][1];
          if (newAmount !== 0) {
            // Update amount for price level
            state.bids[i][1] = newAmount;
          } else {
            // Remove price level, if order are out of stock
            ordersToRemove.push(i);
            ordersCounter--;
          }
        } else {
          if (ordersCounter < 500) {
            let newAmount = +updatedOrders[i][1];
            if(newAmount !== 0) {
              // Add new price level if there are less than 500 orders in order book
              // and amount for this price level greater than 0
              ordersToAdd.push(updatedOrders[i]);
            }
          }
        }

      }

      // Remove outdated orders (array of indexes, elem === index)
      ordersToRemove.forEach(elem => state.asks.splice(ordersToRemove[elem], 1));

      // Add new orders (array of elements, elem === [price, amount])
      ordersToAdd.forEach((elem, index) => state.asks.push(ordersToAdd[index]));

      function binarySearch(sortedArray, key){
        let start = 0;
        let end = sortedArray.length - 1;
    
        while (start <= end) {
          let middle = Math.floor((start + end) / 2);
    
          if (sortedArray[middle] === key) {
              // Found the key
              return middle;
          } else if (sortedArray[middle] < key) {
              // Continue searching to the right
              start = middle + 1;
          } else {
              // Continue searching to the left
              end = middle - 1;
          }
        }
        // key wasn't found
        return -1;
      }

      // Filter and sort updated orders array
      state.asks = state.asks.filter(value => +value[0] >= bestAsk);
      state.asks.sort((a, b) => +a[0] - +b[0]);
    },

    setUpdatedBids: (state, wsData) => {
      state.updatedBids = wsData.data.b;

      let ordersCounter = state.bids.length;
      let ordersToAdd = [];
      let ordersToRemove = [];

      // Get current price levels from state
      let currentPrices = [];
      state.bids.forEach(elem => currentPrices.push(+elem[0]))
      currentPrices.sort((a, b) => a - b);

      // Sort an updated array and get best bid
      let updatedOrders = wsData.data.b;
      let updatedPricesSorted = updatedOrders.map(elem => +elem[0]);
      let bestBid = updatedPricesSorted.sort((a, b) => +b[0] - +a[0])[0];

      // Find updated price in current prices
      for (let i = 0; i < updatedPricesSorted.length; i++) {
        // Search for price
        let priceIndex = binarySearch(currentPrices, updatedPricesSorted[i]);
        
        if (priceIndex !== -1) {
          // Price level needs to be updated
          let newAmount = +updatedOrders[i][1];

          if (newAmount !== 0) {
            // Update amount for price level
            state.bids[i][1] = newAmount;
          } else {
            // Remove price level, if order are out of stock
            ordersToRemove.push(i);
            ordersCounter--;
          }
        } else {
          if (ordersCounter < 500) {
            let newAmount = +updatedOrders[i][1];
            if(newAmount !== 0) {
              // Add new price level if there are less than 500 orders in order book
              // and amount for this price level greater than 0
              ordersToAdd.push(updatedOrders[i]);
            }
          }
        }

      }

      // Remove outdated orders (array of indexes, elem === index)
      ordersToRemove.forEach(elem => state.bids.splice(ordersToRemove[elem], 1));

      // Add new orders (array of elements, elem === [price, amount])
      ordersToAdd.forEach((elem, index) => state.bids.push(ordersToAdd[index]));

      // Filter and sort updated orders array
      state.bids = state.bids.filter(value => +value[0] <= bestBid);
      state.bids.sort((a, b) => +b[0] - +a[0]);

      function binarySearch(sortedArray, key){
        let start = 0;
        let end = sortedArray.length - 1;
    
        while (start <= end) {
            let middle = Math.floor((start + end) / 2);
    
            if (sortedArray[middle] === key) {
                // Found the key
                return middle;
            } else if (sortedArray[middle] < key) {
                // Continue searching to the right
                start = middle + 1;
            } else {
                // Continue searching to the left
                end = middle - 1;
            }
        }
        // key wasn't found
        return -1;
      }
    },

    setUpdatedData: (state, wsData) => {
      let updates = state.updatesArray;

      updates.unshift({
        currency: state.currentCurrency,
        bids: wsData.data.b.length,
        asks: wsData.data.a.length,
        currentId: wsData.data.U,
        })
        
      state.updatesArray = updates.slice(0,9);
    },

    clearState: (state) => {
      state.wsConnection.close(1000);
      state.wsConnection = null;
      state.bids = [];
      state.asks = [];
      state.updatedBids = [];
      state.updatedAsks = [];
      state.orderBookLastUpdateId = null;
    },

    setCurrency: (state, currency) => {
      state.currentCurrency = currency;
      state.updatesArray.unshift({
        currency: "Смена валюты"
      })
    },

    setWebSocket: (state, ws) => {
      state.wsConnection = ws;
    }
  },
  actions: {
    async getOrderBook({commit}) {
      const orderBook = await fetch(`https://api.binance.com/api/v3/depth?symbol=${this.state.currentCurrency}&limit=500`).then(res => res.json());
      
      commit("setOrderBook", orderBook);
    },

    getOrderBookUpdate({commit}) {
      let ws = new WebSocket(`wss://stream.binance.com:9443/ws/${this.state.currentCurrency.toLowerCase()}@depth@1000ms`);
      ws.onmessage = (e) => {
        let wsData = {
          data: JSON.parse(e.data),
          webSocket: ws
        };
        if (this.state.orderBookLastUpdateId < wsData.data.u) {
          commit("setUpdatedAsks", wsData);
          commit("setUpdatedBids", wsData);
          commit("setUpdatedData", wsData);
          commit("setWebSocket", wsData.webSocket);
        } else {
          return
        }
      }
    },

    changeCurrency({commit}, event) {
      commit("clearState");
      commit("setCurrency", event.target.value);
    }
  },
  getters: {
    getBids: (state) => state.bids,
    getAsks: (state) => state.asks,
    getUpdatedBids: (state) => state.updatedBids,
    getUpdatedAsks: (state) => state.updatedAsks,
    getCurrentCurrency: (state) => state.currentCurrency,
    getUpdateData: (state) => state.updatesArray
  }
})
